FROM TBL_INOUT_ORDERS O
LEFT JOIN TBL_COM_PLANT P ON O.PLANTCD = P.PLANTCD
LEFT JOIN TBL_COM_COMPANY C ON O.COMPANYCD = C.COMPANYCD

    O.USEYN = 1
    AND O.ORDERDT >= #{start_date}
    AND O.ORDERDT <= #{end_date}
    AND O.PLANTCD = #{plant_cd}
    AND O.COMPANYCD = #{company_cd}
    AND (C.COMPANYNM LIKE #{search})

